static const uint8_t SBOX[256] = {0x63,0x7c,0x77,0x7b,0xf2,0x6b,0x6f,0xc5,0x30,0x01,0x67,0x2b,0xfe,0xd7,0xab,0x76,0xca,0x82,0xc9,0x7d,0xfa,0x59,0x47,0xf0,0xad,0xd4,0xa2,0xaf,0x9c,0xa4,0x72,0xc0,0xb7,0xfd,0x93,0x26,0x36,0x3f,0xf7,0xcc,0x34,0xa5,0xe5,0xf1,0x71,0xd8,0x31,0x15,0x04,0xc7,0x23,0xc3,0x18,0x96,0x05,0x9a,0x07,0x12,0x80,0xe2,0xeb,0x27,0xb2,0x75,0x09,0x83,0x2c,0x1a,0x1b,0x6e,0x5a,0xa0,0x52,0x3b,0xd6,0xb3,0x29,0xe3,0x2f,0x84,0x53,0xd1,0x00,0xed,0x20,0xfc,0xb1,0x5b,0x6a,0xcb,0xbe,0x39,0x4a,0x4c,0x58,0xcf,0xd0,0xef,0xaa,0xfb,0x43,0x4d,0x33,0x85,0x45,0xf9,0x02,0x7f,0x50,0x3c,0x9f,0xa8,0x51,0xa3,0x40,0x8f,0x92,0x9d,0x38,0xf5,0xbc,0xb6,0xda,0x21,0x10,0xff,0xf3,0xd2,0xcd,0x0c,0x13,0xec,0x5f,0x97,0x44,0x17,0xc4,0xa7,0x7e,0x3d,0x64,0x5d,0x19,0x73,0x60,0x81,0x4f,0xdc,0x22,0x2a,0x90,0x88,0x46,0xee,0xb8,0x14,0xde,0x5e,0x0b,0xdb,0xe0,0x32,0x3a,0x0a,0x49,0x06,0x24,0x5c,0xc2,0xd3,0xac,0x62,0x91,0x95,0xe4,0x79,0xe7,0xc8,0x37,0x6d,0x8d,0xd5,0x4e,0xa9,0x6c,0x56,0xf4,0xea,0x65,0x7a,0xae,0x08,0xba,0x78,0x25,0x2e,0x1c,0xa6,0xb4,0xc6,0xe8,0xdd,0x74,0x1f,0x4b,0xbd,0x8b,0x8a,0x70,0x3e,0xb5,0x66,0x48,0x03,0xf6,0x0e,0x61,0x35,0x57,0xb9,0x86,0xc1,0x1d,0x9e,0xe1,0xf8,0x98,0x11,0x69,0xd9,0x8e,0x94,0x9b,0x1e,0x87,0xe9,0xce,0x55,0x28,0xdf,0x8c,0xa1,0x89,0x0d,0xbf,0xe6,0x42,0x68,0x41,0x99,0x2d,0x0f,0xb0,0x54,0xbb,0x16};
static uint8_t xtime(uint8_t a){return(a&0x80)?((a<<1)^0x1B):(a<<1);}
static void aes_enc(uint8_t s[16],const uint8_t rk[176]){int i;for(i=0;i<16;i++)s[i]^=rk[i];for(int r=1;r<10;r++){for(i=0;i<16;i++)s[i]=SBOX[s[i]];uint8_t t;t=s[1];s[1]=s[5];s[5]=s[9];s[9]=s[13];s[13]=t;t=s[2];s[2]=s[10];s[10]=t;t=s[6];s[6]=s[14];s[14]=t;t=s[3];s[3]=s[15];s[15]=s[11];s[11]=s[7];s[7]=t;for(int c=0;c<4;c++){uint8_t*x=s+c*4,a=x[0],b=x[1],d=x[2],e=x[3];x[0]=xtime(a)^(xtime(b)^b)^d^e;x[1]=a^xtime(b)^(xtime(d)^d)^e;x[2]=a^b^xtime(d)^(xtime(e)^e);x[3]=(xtime(a)^a)^b^d^xtime(e);}for(i=0;i<16;i++)s[i]^=rk[r*16+i];}for(i=0;i<16;i++)s[i]=SBOX[s[i]];uint8_t t;t=s[1];s[1]=s[5];s[5]=s[9];s[9]=s[13];s[13]=t;t=s[2];s[2]=s[10];s[10]=t;t=s[6];s[6]=s[14];s[14]=t;t=s[3];s[3]=s[15];s[15]=s[11];s[11]=s[7];s[7]=t;for(i=0;i<16;i++)s[i]^=rk[160+i];}
static uint64_t rotr(uint64_t v,int sh){return(v>>sh)|(v<<(64-sh));}
static void ascon_p12(uint64_t*x0,uint64_t*x1,uint64_t*x2,uint64_t*x3,uint64_t*x4){const uint8_t RC[12]={0xf0,0xe1,0xd2,0xc3,0xb4,0xa5,0x96,0x87,0x78,0x69,0x5a,0x4b};for(int r=0;r<12;r++){*x0^*x4;*x4^*x3;*x2^*x1;uint64_t t0=*x0,t1=*x1,t2=*x2,t3=*x3,t4=*x4;*x0^=(~t1&t2);*x1^=(~t2&t3);*x2^=(~t3&t4);*x3^=(~t4&t0);*x4^=(~t0&t1);*x2=~*x2;*x4=~*x4;*x1^*x0;*x0^*x4;*x3^*x2;*x0^=rotr(*x0,19)^rotr(*x0,28);*x1^=rotr(*x1,61)^rotr(*x1,39);*x2^=rotr(*x2,1)^rotr(*x2,6);*x3^=rotr(*x3,10)^rotr(*x3,17);*x4^=rotr(*x4,7)^rotr(*x4,41);*x2^=RC[r];}}
static void tj_update(uint32_t s[4],const uint32_t key[4]){for(int i=0;i<32;i++){uint32_t s47=(s[2]<<17)|(s[1]>>15),s70=(s[3]<<26)|(s[2]>>6),s85=(s[3]<<11)|(s[2]>>21),s91=(s[3]<<5)|(s[2]>>27),fb=s[0]^s47^(~(s70&s85))^s91^key[i&3];s[0]=s[1];s[1]=s[2];s[2]=s[3];s[3]=fb;}}

int main(void){
    volatile unsigned long sink=0; clock_t t0,t1; unsigned long ta,tb,tc; FILE *f=fopen("bench_edge_result.txt","w");
    uint8_t rk[176],st[16]={0};for(int i=0;i<176;i++)rk[i]=(uint8_t)(i*7+13);
    t0=clock();for(int n=0;n<ITERATIONS;n++){memcpy(st,rk,16);st[0]^=n;aes_enc(st,rk);sink^=st[0];}t1=clock();ta=(unsigned long)(t1-t0);
    uint64_t x0=0x80400c0600000000ULL,x1=0,x2=0,x3=0,x4=0;
    t0=clock();for(int n=0;n<ITERATIONS;n++){x0=0x80400c0600000000ULL^(n&0xFF);x1=x2=x3=x4=n;ascon_p12(&x0,&x1,&x2,&x3,&x4);sink^=x0;}t1=clock();tb=(unsigned long)(t1-t0);
    uint32_t tj_s[4]={0},tj_k[4]={0x01234567,0x89ABCDEF,0x01234567,0x89ABCDEF};
    t0=clock();for(int n=0;n<ITERATIONS;n++){tj_s[0]=n;tj_s[1]=n+1;tj_s[2]=n+2;tj_s[3]=n+3;tj_update(tj_s,tj_k);sink^=tj_s[0];}t1=clock();tc=(unsigned long)(t1-t0);
    fprintf(f,"%lu %lu %lu %lu\n",ta,tb,tc,sink); fclose(f); return 0;
}
